module.exports = function(RED) {
    "use strict";

    function NeuralInputNode(n) {
        RED.nodes.createNode(this, n);
        var node = this;
        node.values = n.values || [0.5, 0.5, 0.5];
        node.count = n.count || 3;

        node.on("input", function(msg, send, done) {
            var vals = node.values.slice();
            while (vals.length < node.count) {
                vals.push(0);
            }
            vals.length = node.count;
            msg.payload = vals;
            msg.neural = msg.neural || {};
            msg.neural.type = "input";
            msg.neural.shape = [vals.length];

            var active = vals.filter(function(v) { return v > 0; }).length;
            node.status({ fill: active > 0 ? "green" : "grey", shape: "dot", text: vals.map(function(v) { return v.toFixed(2); }).join(", ") });

            send(msg);
            done();
        });
    }

    RED.nodes.registerType("neural-input", NeuralInputNode);
};
